/** <module> im_glossary
 *
 *  Illustrative Mathematics K-8 glossary terms as facts.
 *
 *  Generated by scripts/process_glossary.py from the per-grade glossary
 *  pages at accessim.org (saved copies, retrieved 2026-07-13; the saved
 *  pages are not retained in the repo). Definitions and figure alt text
 *  are by Illustrative Mathematics, CC BY 4.0
 *  (https://creativecommons.org/licenses/by/4.0/), reformatted for fact
 *  storage: MathJax math appears as its LaTeX source, figures as
 *  [figure: <alt text>] lines. A rendered companion with the original
 *  definition HTML lives at
 *  IM_Supplementary_Materials/simplified_glossary.html.
 *
 *  Lesson links appear only on grade 6-8 entries; IM's K-5 glossary
 *  pages do not reference lessons. Lesson IDs use the repo's canonical
 *  'IM-G<g>-U<u>-L<l>' form, so they join against
 *  explicit_lesson_strategy/4, vision_lesson_strategy/4, and the
 *  Learning Commons spine. Do not hand-edit.
 */
:- module(im_glossary,
          [ im_glossary_term/6,
            im_glossary_in_lesson/3,
            im_glossary_lesson_url/2,
            grade_name/2
          ]).

:- use_module(library(lists), [member/2]).

%!  im_glossary_in_lesson(?Grade, ?TermSlug, ?LessonId) is nondet.
%
%   Join surface: the grade-level glossary links TermSlug to LessonId.
im_glossary_in_lesson(Grade, TermSlug, LessonId) :-
    im_glossary_term(Grade, TermSlug, _, _, _, LessonIds),
    member(LessonId, LessonIds).

% grade_name(GradeCode, GradeName)
grade_name('G1', 'Grade 1').
grade_name('G2', 'Grade 2').
grade_name('G3', 'Grade 3').
grade_name('G4', 'Grade 4').
grade_name('G5', 'Grade 5').
grade_name('G6', 'Grade 6').
grade_name('G7', 'Grade 7').
grade_name('G8', 'Grade 8').
grade_name('GK', 'Kindergarten').

