im_glossary_term('G5', 'rectangular_prism', "rectangular prism", "A solid figure with 6 faces that are all rectangles.", "", []).
im_glossary_term('G5', 'rhombus', "rhombus", "A quadrilateral with 4 equal sides.", "", []).
im_glossary_term('G5', 'right_triangle', "right triangle", "A triangle with a 90-degree angle.", "", []).
im_glossary_term('G5', 'square', "square", "A quadrilateral with 4 equal sides and 4 right angles.", "", []).
im_glossary_term('G5', 'standard_algorithm_for_multiplication', "standard algorithm (for multiplication)", "A set of steps used to multiply numbers by place value. Write the numbers vertically, with the digits lined up by place value. Starting with the least place value, multiply the digits in each place of the bottom number by the digits in each place of the top number. Compose units in each place, as needed, representing that unit with a number over the place value to the left of the digit being multiplied. Add the partial products, including composed units.", "", []).
im_glossary_term('G5', 'trapezoid', "trapezoid", "A quadrilateral with at least 2 parallel opposite sides.", "", []).
im_glossary_term('G5', 'unit_cube', "unit cube", "A cube whose sides are each 1 unit long. Unit cubes are used to measure volume.", "", []).
im_glossary_term('G5', 'vertical_axis', "vertical axis", "The number line that runs up and down in a pair of axes.", "", []).
im_glossary_term('G5', 'volume', "volume", "The number of unit cubes that fill a solid figure without gaps or overlap.", "", []).
im_glossary_term('G6', 'absolute_value', "absolute value", "The absolute value of a number is its distance from 0 on the number line.\n- The absolute value of -7 is 7, because it is 7 units away from 0.\n- The absolute value of 5 is 5, because it is 5 units away from 0.\n[figure: Horizontal number line, tick marks every 1 unit from -7 to 7. Above, there is a horizontal segment from -7 to 0 labeled 7, and a horizontal segment from 0 to 5 labeled 5.]", "glossary_assets/g6_absolute_value.svg", ['IM-G6-U7-L6']).
im_glossary_term('G6', 'area', "area", "Area is the number of square units that cover a two-dimensional region without gaps or overlaps.\n- The area of region A is 8 square units.\n- The area of the shaded region of B is \\frac12 square unit.\n[figure: Figure A on the left composed of 8 identical shaded squares arranged in 3 rows. Figure B on the right consists of one square with a diagonal segment from corner to corner. Half of the square is shaded.]", "glossary_assets/g6_area.svg", ['IM-G6-U1-L2']).
im_glossary_term('G6', 'average', "average", "The average is another name for the mean of a data set. To find the average, add all the numbers in the data set. Then divide by how many numbers there are.\n- Data set: 3, 5, 6, 8, 11, 12\n- 3+5+6+8+11+12=45\n- 45 \\div 6 = 7.5\nThe average is 7.5.", "", ['IM-G6-U8-L9']).
im_glossary_term('G6', 'base_of_a_parallelogram_or_triangle', "base (of a parallelogram or triangle)", "Any side of a parallelogram or triangle can be chosen its base. The length of this side is also called the base.\n[figure: Three identical, scalene, obtuse triangles oriented the same way. Each triangle has a different one of its sides labeled base.]", "glossary_assets/g6_base_of_a_parallelogram_or_triangle.svg", ['IM-G6-U1-L5']).
im_glossary_term('G6', 'base_of_a_prism_or_pyramid', "base (of a prism or pyramid)", "A base is a specific face of a prism or pyramid.\nA prism has 2 identical bases that are parallel. A pyramid has 1 base.\nA prism or pyramid is named for the shape of its base.\n[figure: A pentagonal prism. There are two identical pentagons on the top and bottom. Each vertex of a pentagon is connected by a vertical segment to the corresponding vertex of the other pentagons. The pengatons are each shaded, with the word base pointing to each.]\n[figure: A hexagonal pyramid. There is a hexagon on the bottom shaded green. From a point above the hexagon extend 6 segments, each connected to a vertex of the hexagon.]", "glossary_assets/g6_base_of_a_prism_or_pyramid_0.svg", ['IM-G6-U1-L13']).
im_glossary_term('G6', 'box_plot', "box plot", "A box plot is a way to represent data on a number line with a box and some lines. The data is divided into four sections by 5 values. Those values are the minimum, first quartile, median, third quartile, and maximum.\n[figure: Box plot from 0 to 16 by 2’s. Number of books. Whisker from 0 to 5. Box from 5 to 10 with vertical line at 6. Whisker from 10 to 15.]", "glossary_assets/g6_box_plot.svg", ['IM-G6-U8-L16']).
im_glossary_term('G6', 'categorical_data', "categorical data", "A set of categorical data has values that are words instead of numbers.\nFor example, Han asks 5 friends to each name their favorite color. Their answers are “blue,” “blue,” “green,” “blue,” and “orange.”", "", ['IM-G6-U8-L1']).
im_glossary_term('G6', 'center', "center", "The center of a data set is a value in the middle. It represents a typical value for the data set.\nThe center of this data set is between 4.5 and 5 kilograms. So a typical cat in this group weighs between 4.5 and 5 kilograms.\n[figure: Dot plot from 2 to 12 by 1’s. Cat weights in kilograms. Beginning at 3, number of dots above each increment is 2, 4, 4, 5, 5, 4, 3, 3, 1.]", "glossary_assets/g6_center.svg", ['IM-G6-U8-L5']).
im_glossary_term('G6', 'coefficient', "coefficient", "A coefficient is a number that is multiplied by a variable.\n- In the expression 3x+5 , the coefficient of x is 3.\n- In the expression y+5 , the coefficient of y is 1, because y=1 \\boldcdot y .", "", ['IM-G6-U6-L2']).
im_glossary_term('G6', 'common_factor', "common factor", "A common factor of two numbers is a number that evenly divides both numbers.\n- The factors of 15 are 1, 3, 5, and 15.\n- The factors of 20 are 1, 2, 4, 5, 10, and 20.\nThe common factors of 15 and 20 are 1 and 5.", "", ['IM-G6-U7-L16']).
im_glossary_term('G6', 'common_multiple', "common multiple", "A common multiple of two numbers is a product that results from multiplying each of the two numbers by some whole number.\n- The multiples of 3 are 3, 6, 9, 12, 15, 18, 21, 24, 27, 30, 33, . . . .\n- The multiples of 5 are 5, 10, 15, 20, 25, 30, 35, 40, . . . .\nThe common multiples of 3 and 5 are 15, 30, 45, 60, . . . .", "", ['IM-G6-U7-L17']).
im_glossary_term('G6', 'compose', "compose", "The word compose means “put together.” To compose a shape, put figures together to make a new shape.\n[figure: Image on left shows three separate parts of a shape; image on right shows those three parts put together to create an oval.]", "glossary_assets/g6_compose.svg", []).
im_glossary_term('G6', 'constant_speed', "constant speed", "When an object moves at a constant speed, it moves at the same speed at all times. It does not move faster or slower at any time. So, the ratios of distance traveled to elapsed time are always equivalent.\nFor example, a car moves at a constant speed of 50 miles per hour. This means it travels 50 miles in 1 hour, 100 miles in 2 hours, and 150 miles in 3 hours. The ratios of distance in miles to time in hours are equivalent.", "", ['IM-G6-U2-L9']).
im_glossary_term('G6', 'coordinate_plane', "coordinate plane", "The coordinate plane is one way to represent pairs of numbers. The plane is made of a horizontal number line and a vertical number line that cross at 0.\nPairs of numbers can be used to describe the location of a point in the coordinate plane.\nPoint R is located at (3,\\text-2) . This means R is 3 units to the right and 2 units down from (0,0) .\n[figure: Point R on a coordinate plane. Horizontal and vertical axis scale negative 4 to 4 by 1’s. The point has coordinates R 3 comma negative 2.]", "glossary_assets/g6_coordinate_plane.svg", ['IM-G6-U7-L11']).
im_glossary_term('G6', 'cubed', "cubed", "The word cubed means “to the third power.” This is because a cube with side length s has a volume of s \\boldcdot s \\boldcdot s , or s^3 .", "", ['IM-G6-U1-L17']).
im_glossary_term('G6', 'decompose', "decompose", "The word decompose means “take apart.” To decompose a shape, take it apart to make more than one new shape.\n[figure: Image on left shows three parts put together to create an oval; the image on the right shows the oval separated into the three parts.]", "glossary_assets/g6_decompose.svg", []).
im_glossary_term('G6', 'dependent_variable', "dependent variable", "The dependent variable is the result of a calculation.\nFor example, a boat travels at a constant speed of 25 miles per hour. The equation d=25t describes the relationship between the boat's distance and time. The dependent variable is the distance traveled because d is the result of multiplying 25 by t .\n[figure: A graph of 10 points plotted in the coordinate plane.]", "glossary_assets/g6_dependent_variable.svg", ['IM-G6-U6-L16']).
im_glossary_term('G6', 'distribution', "distribution", "The distribution of a data set tells how many times each value occurs.\n- In the data set blue, blue, green, blue, orange, the distribution is 3 blues, 1 green, and 1 orange.\n-\nThis dot plot shows the distribution for the data set 6, 10, 7, 35, 7, 36, 32, 10, 7, 35 kilograms.\n[figure: a dot plot that shows the distribution for the data set 6, 10, 7, 35, 7, 36, 32, 10, 7, 35.]", "glossary_assets/g6_distribution.svg", ['IM-G6-U8-L3']).
im_glossary_term('G6', 'dot_plot', "dot plot", "A dot plot is a way to represent data with dots. Each dot above a number shows one time the value occurs in the set.\n[figure: a dot plot representing plant heights]", "glossary_assets/g6_dot_plot.svg", ['IM-G6-U8-L1']).
im_glossary_term('G6', 'double_number_line_diagram', "double number line diagram", "A double number line diagram uses a pair of parallel number lines to represent equivalent ratios. There is one number line for each quantity in the ratio. The tick marks for equivalent ratios line up.\nThis double number line diagram shows that 3:5 and 6:10 are equivalent ratios.\n[figure: A double number line for teaspoons of red paint: 0, 3, 6, 9, 12 and teaspoons of yellow paint: 0, 5, 10, 15, 20.]", "glossary_assets/g6_double_number_line_diagram.svg", ['IM-G6-U2-L6']).
im_glossary_term('G6', 'edge', "edge", "Each side of a polygon is called an edge.\nThe edges of this polygon are segments AB , BC , CD , DE , and EA .\n[figure: Polygon with 5 sides]", "glossary_assets/g6_edge.png", ['IM-G6-U1-L10']).
im_glossary_term('G6', 'equivalent_expressions', "equivalent expressions", "Equivalent expressions are always equal to each other. If the expressions have variables, they are equal whenever the same value is used for the variable in each expression.\nFor example, 3x+4x is equivalent to 5x+2x .\n- When x is 3, both expressions equal 21.\n- When x is 10, both expressions equal 70.\n- When x is any other number, both expressions still have equal value.", "", ['IM-G6-U6-L8']).
im_glossary_term('G6', 'equivalent_ratios', "equivalent ratios", "Two ratios are equivalent if each of the numbers in the first ratio can be multiplied by the same factor to get the numbers in the second ratio. For example, 8:6 is equivalent to 4:3 , because 8\\boldcdot\\frac12 = 4 and 6\\boldcdot\\frac12 = 3 .\nA recipe for lemonade says to use 8 cups of water and 6 lemons. If 4 cups of water and 3 lemons are used, it will make half as much lemonade. Both recipes taste the same, because 8:6 and 4:3 are equivalent ratios.\ncups of water\nnumber of lemons\n8\n6\n4\n3", "", ['IM-G6-U2-L5']).
im_glossary_term('G6', 'exponent', "exponent", "In expressions like 5^3 and 8^2 , the numbers 3 and the 2 are called exponents. They tell how many times a number is used as a factor.\nFor example, 5^3 = 5 \\boldcdot 5 \\boldcdot 5 , and 8^2 = 8 \\boldcdot 8 .", "", ['IM-G6-U1-L17']).
im_glossary_term('G6', 'face', "face", "Each flat side of a polyhedron is called a face.\nFor example, a cube has 6 faces that are all squares.", "", ['IM-G6-U1-L12']).
im_glossary_term('G6', 'frequency', "frequency", "The frequency of a data value is how many times it occurs in the data set.\nFor example, there are 20 dogs in a park. The table shows the frequency of each color.\ndog color\nfrequency\nwhite\n4\nbrown\n7\nblack\n3\nmulti-color\n6", "", ['IM-G6-U8-L3']).
im_glossary_term('G6', 'greatest_common_factor_gcf', "greatest common factor (GCF)", "The greatest common factor of two numbers is the largest number that evenly divides both numbers.\n- The factors of 45 are 1, 3, 5, 9, 15, and 45.\n- The factors of 60 are 1, 2, 3, 4, 5, 6, 10, 12, 15, 20, 30, and 60.\nThe greatest common factor of 45 and 60 is 15.", "", ['IM-G6-U7-L16']).
im_glossary_term('G6', 'height_of_a_parallelogram_or_triangle', "height (of a parallelogram or triangle)", "The height is the shortest distance from the base of the shape to the opposite side (for a parallelogram) or to the opposite vertex (for a triangle).\nThe height can be shown in more than one place. It is always perpendicular to the chosen base.\n[figure: 2 parallelograms with height and base measurements]", "glossary_assets/g6_height_of_a_parallelogram_or_triangle.svg", ['IM-G6-U1-L5']).
im_glossary_term('G6', 'histogram', "histogram", "A histogram is a way to represent data on a number line with bars. Data values are grouped by ranges. The height of each bar shows how many data values are in that range. Each bar includes the left-end value but not the right-end value.\n[figure: histogram showing number of tickets]", "glossary_assets/g6_histogram.svg", ['IM-G6-U8-L6']).
im_glossary_term('G6', 'independent_variable', "independent variable", "The independent variable is used to calculate the value of another variable.\nFor example, a boat travels at a constant speed of 25 miles per hour. The equation d=25t describes the relationship between the boat's distance and time. The independent variable is time because t is multiplied by 25 to get d .\n[figure: A graph of 10 points plotted in the coordinate plane.]", "glossary_assets/g6_independent_variable.svg", ['IM-G6-U6-L16']).
im_glossary_term('G6', 'inequality', "inequality", "An inequality is a statement that compares two values or expressions using symbols such as “ > ” or “ ”.\n- The symbol “ > ” means “is greater than.”\n- The symbol “ ” means “is less than.”\nFor example, the inequality \\text-3 > \\text-7 tells us that -3 is greater than -7.", "", ['IM-G6-U7-L3']).
im_glossary_term('G6', 'interquartile_range_iqr', "interquartile range (IQR)", "The interquartile range is one way to measure how spread out a data set is. To find the IQR, subtract the first quartile (Q1) from the third quartile (Q3).\nFor example, the IQR of this data set is 20 because 50-30=20 .\n22\n29\n30\n31\n32\n43\n44\n45\n50\n50\n59\nQ1\nQ2\nQ3", "", ['IM-G6-U8-L15']).
im_glossary_term('G6', 'least_common_multiple_lcm', "least common multiple (LCM)", "The least common multiple of two numbers is the smallest product that results from multiplying each of the two numbers by some whole number.\n- The multiples of 6 are 6, 12, 18, 24, 30, 36, 42, 48, 54, 60, . . . .\n- The multiples of 10 are 10, 20, 30, 40, 50, 60, 70, 80, . . . .\nThe least common multiple of 6 and 10 is 30.", "", ['IM-G6-U7-L17']).
im_glossary_term('G6', 'long_division', "long division", "Long division is a way to show the steps for dividing numbers in decimal form. It finds the quotient one digit at a time, from left to right.\nHere is the long division for 512 \\div 4 .", "glossary_assets/g6_long_division.svg", ['IM-G6-U5-L11']).
im_glossary_term('G6', 'mean', "mean", "The mean is one way to measure the center of a data set. It can be thought of as a balance point. To find the mean, add all the numbers in the data set. Then divide by how many numbers there are.\n- Data set: 7, 9, 12, 13, 14\n- Add values: 7+9+12+13+14=55\n- Divide by number of values: 55 \\div 5 = 11\nThe mean is 11. So, the typical travel time is 11 minutes.", "glossary_assets/g6_mean.svg", ['IM-G6-U8-L9']).
im_glossary_term('G6', 'mean_absolute_deviation_mad', "mean absolute deviation (MAD)", "The mean absolute deviation (MAD) is one way to measure how spread out a data set is. To find the MAD, find the distance between each data value and the mean. Add all the distances. Then divide by how many distances there are.\n- Data set: 7, 9, 12, 13, 14\n- Add distances: 4+2+1+2+3=12\n- Divide by number of distances: 12 \\div 5 = 2.4\nThe MAD is 2.4. So, these travel times are typically 2.4 minutes away from the mean of 11 minutes.\n[figure: data set for travel time in minutes with a mean of 11 minutes]", "glossary_assets/g6_mean_absolute_deviation_mad.svg", ['IM-G6-U8-L11']).
im_glossary_term('G6', 'measure_of_center', "measure of center", "A measure of center is a value that seems typical for a data distribution.\nMean and median are both measures of center.", "", ['IM-G6-U8-L10']).
im_glossary_term('G6', 'median', "median", "The median is one way to measure the center of a data set. It is the middle number when the data set is listed in order of value.\n- For the data set 7, 9, 12, 13, 14, the median is 12.\n- For the data set 3, 5, 6, 8, 11, 12, there are 2 numbers in the middle. The median is the average of these 2 numbers. 6+8=14 , and 14 \\div 2 = 7 . The median is 7.", "", ['IM-G6-U8-L13']).
im_glossary_term('G6', 'negative_number', "negative number", "A negative number is a number that is less than 0.\n[figure: number line with arrow that extends from 0 to -7]", "glossary_assets/g6_negative_number.svg", ['IM-G6-U7-L1']).
im_glossary_term('G6', 'net', "net", "A net is a two-dimensional figure that can be folded to make a three-dimensional figure.\nHere is a net for a cube.\n[figure: Six squares arranged with 4 in a row, 1 above the second square in the row, and one below the second square in the row.]", "glossary_assets/g6_net.svg", ['IM-G6-U1-L13']).
im_glossary_term('G6', 'numerical_data', "numerical data", "A set of numerical data has values that are numbers.\nFor example, Han lists the ages of people in his family: 7, 10, 12, 36, 40, 67.", "", ['IM-G6-U8-L1']).
im_glossary_term('G6', 'opposite', "opposite", "Two numbers are opposites if they are the same distance from 0 on the number line, but on different sides. One is negative, and the other is positive.\n[figure: used in:]", "glossary_assets/g6_opposite.svg", ['IM-G6-U7-L2']).
im_glossary_term('G6', 'opposite_vertex', "opposite vertex", "For each side of a triangle, there is 1 vertex that is not on that side. This is the opposite vertex.\nPoint A is the opposite vertex to side BC .\n[figure: triangle with points labeled A, B, C.]", "glossary_assets/g6_opposite_vertex.svg", ['IM-G6-U1-L9']).
im_glossary_term('G6', 'pace', "pace", "Pace is one way to describe how fast something moves. Pace tells how much time it takes the object to travel a certain distance.\nFor example, Diego runs at a pace of 10 minutes per mile. Elena runs at a pace of 11 minutes per mile. Elena runs slower than Diego, because it takes her more time to travel the same distance.", "", ['IM-G6-U3-L9']).
im_glossary_term('G6', 'parallelogram', "parallelogram", "A parallelogram is a type of quadrilateral that has 2 pairs of parallel sides.\nHere are 2 examples of parallelograms.\n[figure: Parallelogram with the angles and side lengths provided. Top and bottom sides = 5 units. Left and right sides = 4.24 units. Top left and bottom right angles = 135 degrees. Top right and bottom left angles = 45 degrees.]\n[figure: Parallelogram with the angles and side lengths provided. Top and bottom sides = 9.34 units. Left and right sides = 4 units. Top left and bottom right angles = 27.2 degrees. Top right and bottom left angles = 152.8 degrees.]", "glossary_assets/g6_parallelogram_0.svg", []).
im_glossary_term('G6', 'per', "per", "The word per means “for each.”\nFor example, the price is $5 per ticket. This means $5 must be paid for each ticket. Buying 4 tickets costs $20, because 4 \\boldcdot 5 = 20 .", "", ['IM-G6-U2-L7']).
im_glossary_term('G6', 'percent', "percent", "The word percent means “for each 100.” The symbol for percent is %.\nFor example, a quarter is worth 25 cents, and a dollar is worth 100 cents. A quarter is worth 25% of a dollar.\n[figure: A quarter (coin)]\n[figure: A diagram of two bars with different lengths.]", "glossary_assets/g6_percent_0.png", ['IM-G6-U3-L10']).
im_glossary_term('G6', 'percentage', "percentage", "A percentage is a rate per 100.\nFor example, a fish tank can hold 36 liters. There are 27 liters of water in the tank. The percentage of the tank that is full is 75%.\n[figure: a double number line]", "glossary_assets/g6_percentage.svg", ['IM-G6-U3-L10']).
im_glossary_term('G6', 'polygon', "polygon", "A polygon is a closed, two-dimensional shape with straight sides that do not cross each other.\nFigure ABCDE is an example of a polygon.\n[figure: Polygon with 5 sides]", "glossary_assets/g6_polygon.svg", ['IM-G6-U1-L11']).
im_glossary_term('G6', 'polyhedron', "polyhedron", "A polyhedron is a closed, three-dimensional shape with flat sides. When there is more than one polyhedron, they are called polyhedra.\nHere are some drawings of polyhedra.\n[figure: 3 polyhedra, from left to right shapes resemble a house, drum, and star.]", "glossary_assets/g6_polyhedron.png", ['IM-G6-U1-L13']).
im_glossary_term('G6', 'positive_number', "positive number", "A positive number is a number that is greater than 0.\n[figure: Number line with green arrow extending from 0 to 7]", "glossary_assets/g6_positive_number.svg", ['IM-G6-U7-L1']).
im_glossary_term('G6', 'prism', "prism", "A prism is a type of polyhedron with 2 bases that are identical and parallel. The bases are connected by parallelograms.\nHere are some drawings of prisms.\n[figure: A triangular prism.]\n[figure: A pentagonal prism.]\n[figure: A rectangular prism.]", "glossary_assets/g6_prism_0.svg", ['IM-G6-U1-L13']).
im_glossary_term('G6', 'pyramid', "pyramid", "A pyramid is a type of polyhedron that has 1 base. All the other faces are triangles that meet at a single vertex.\nHere are some drawings of pyramids.\n[figure: A rectangular pyramid.]\n[figure: A hexagonal pyramid.]\n[figure: A heptagonal pyramid.]", "glossary_assets/g6_pyramid_0.svg", ['IM-G6-U1-L13']).
im_glossary_term('G6', 'quadrant', "quadrant", "The coordinate plane is divided into 4 sections called quadrants. The quadrants are numbered using Roman numerals, as shown.\n[figure: A coordinate plane, origin O. The area top and right of the origin is Quadrant 1, and counter-clockwise labeled quadrant 2, 3, 4.]", "glossary_assets/g6_quadrant.svg", ['IM-G6-U7-L11']).
im_glossary_term('G6', 'quadrilateral', "quadrilateral", "A quadrilateral is a type of polygon that has 4 sides.\n- A rectangle is an example of a quadrilateral.\n- A pentagon is not a quadrilateral, because it has 5 sides.", "", []).
im_glossary_term('G6', 'quartile', "quartile", "Quartiles are the numbers that divide a data set into four sections. Each section has the same number of data values.\nIn this data set, the first quartile (Q1) is 30. The second quartile (Q2) is the median, 43. The third quartile (Q3) is 50.\n22\n29\n30\n31\n32\n43\n44\n45\n50\n50\n59\nQ1\nQ2\nQ3", "", ['IM-G6-U8-L15']).
im_glossary_term('G6', 'range', "range", "The range is the distance between the smallest and largest values in a data set.\nIn the data set 3, 5, 6, 8, 11, 12, the range is 9, because 12-3=9 .", "", ['IM-G6-U8-L15']).
im_glossary_term('G6', 'ratio', "ratio", "A ratio is a way to relate 2 or more quantities.\nFor example, the ratio 3:2 could describe:\n- A recipe that uses 3 cups of flour for every 2 eggs.\n- A boat that moves 3 meters every 2 seconds.\n- A diagram that has 3 blue squares for every 2 green squares.\n[figure: a discrete diagram]", "glossary_assets/g6_ratio.svg", ['IM-G6-U2-L1']).
im_glossary_term('G6', 'rational_number', "rational number", "A rational number is a number that can be written as a positive fraction, a negative fraction, or zero.\n- 8 and -8 are rational numbers because they can be written as \\frac81 and \\text-\\frac81 .\n- 0.75 and -0.75 are rational numbers because they can be written as \\frac{75}{100} and \\text-\\frac{75}{100} .", "", ['IM-G6-U7-L2']).
im_glossary_term('G6', 'reciprocal', "reciprocal", "Two numbers that multiply to equal 1 are reciprocals.\n- 8 and \\frac{1}{8} are reciprocals because 8 \\boldcdot \\frac{1}{8} = 1 .\n-\n\\frac{2}{5} is a reciprocal of \\frac{5}{2} because \\frac{2}{5} \\boldcdot \\frac{5}{2} = 1 .", "", ['IM-G6-U4-L11']).
im_glossary_term('G6', 'region', "region", "A region is the space inside of a shape.\n- Examples of two-dimensional regions are the inside of a circle and the inside of a polygon.\n- Examples of three-dimensional regions are the inside of a cube and the inside of a sphere.", "", ['IM-G6-U1-L1']).
im_glossary_term('G6', 'same_rate', "same rate", "The phrase same rate is used to describe two situations that have equivalent ratios.\nFor example, a sink is filled at a rate of 2 gallons per minute. A tub is also filled at a rate of 2 gallons per minute. So, the sink and the tub are filled at the same rate.", "", ['IM-G6-U2-L10']).
im_glossary_term('G6', 'sign', "sign", "The sign of any number other than 0 is either positive or negative.\nFor example, the sign of 6 is positive. The sign of -6 is negative. Zero does not have a sign, because it is not positive or negative.", "", ['IM-G6-U7-L3']).
im_glossary_term('G6', 'solution_to_an_equation', "solution to an equation", "A solution to an equation is a number that can be used in place of the variable to make the equation true.\n- The solution to the equation m+1=8 is 7, because it is true that 7+1=8 .\n- The solution to m+1=8 is not 9, because 9+1 does not equal 8.", "", ['IM-G6-U6-L2']).
im_glossary_term('G6', 'solution_to_an_inequality', "solution to an inequality", "A solution to an inequality is a number that can be used in place of the variable to make the inequality true.\n- A solution to the inequality c is 5, because it is true that 5.\n- Some other solutions to this inequality are 9.9, 0, and -4.", "", ['IM-G6-U7-L9']).
im_glossary_term('G6', 'speed', "speed", "Speed is one way to describe how fast something moves. Speed tells how much distance the object travels in a certain amount of time.\nFor example, Tyler walks at a speed of 4 miles per hour. Priya walks at a speed of 5 miles per hour. Priya walks faster than Tyler, because she travels more distance in the same amount of time.", "", ['IM-G6-U3-L9']).
im_glossary_term('G6', 'spread', "spread", "The spread of a set of data tells how far apart the values are.\nThese dot plots show that the travel times for students in South Africa are more spread out than for students in New Zealand.\n[figure: dot plots showing travel times for students in South Africa and New Zealand]", "glossary_assets/g6_spread.svg", ['IM-G6-U8-L5']).
im_glossary_term('G6', 'squared', "squared", "The word squared means “to the second power.” This is because a square with side length s has an area of s \\boldcdot s , or s^2 .", "", ['IM-G6-U1-L17']).
im_glossary_term('G6', 'statistical_question', "statistical question", "A statistical question can be answered by collecting data that has different values. Here are some examples of statistical questions:\n- Who is the most popular musical artist at your school?\n- When do students in your class typically eat dinner?\n- Which classroom in your school has the most books?", "", ['IM-G6-U8-L2']).
im_glossary_term('G6', 'surface_area', "surface area", "The surface area of a polyhedron is the number of square units that covers all of its faces with no gaps or overlaps.\nFor example, the 6 faces of a cube each have an area of 9 cm2. So, the surface area of the cube is 6 \\boldcdot 9 , or 54 cm2.", "", ['IM-G6-U1-L12']).
im_glossary_term('G6', 'table', "table", "A table organizes information into horizontal rows and vertical columns. The first row or column usually tells what the numbers represent.\nThis table shows the tail lengths of pets. It has 4 rows and 2 columns.\npet\ntail length (inches)\ndog\n22\ncat\n12\nmouse\n2", "", []).
im_glossary_term('G6', 'tape_diagram', "tape diagram", "A tape diagram is a group of rectangles put together to represent a relationship between quantities.\nThis tape diagram shows a ratio of 30 gallons of yellow paint to 50 gallons of blue paint.\n[figure: tape diagrams]\nThis tape diagram represents the equivalent ratio of 15 gallons of yellow paint to 25 gallons of blue paint.\n[figure: This tape diagram represents the equivalent ratio of 15 gallons of yellow paint to 25 gallons of blue paint.]", "glossary_assets/g6_tape_diagram_0.svg", ['IM-G6-U2-L15']).
im_glossary_term('G6', 'term', "term", "A term is a part of an expression. It can be a single number, a variable, or a number and a variable that are multiplied together.\n- 7, y , and 9a are examples of terms.\n- The expression 5x+3 has 2 terms: 5x and 3 .", "", ['IM-G6-U6-L10']).
im_glossary_term('G6', 'unit_price', "unit price", "The unit price is the cost for 1 item or for 1 unit of measure.\nFor example, 10 feet of fencing costs $150. The unit price is 150 \\div 10 , or $15 per foot.", "", ['IM-G6-U2-L8']).
im_glossary_term('G6', 'unit_rate', "unit rate", "A unit rate is a rate per 1.\nFor example, 12 people share 2 pies equally. One unit rate is 6 people per pie, because 12 \\div 2 = 6 . The other unit rate is \\frac16 of a pie per person, because 2 \\div 12 = \\frac16 .", "", ['IM-G6-U3-L5']).
im_glossary_term('G6', 'variability', "variability", "The variability of a data set describes how different the values are.\nData set B has many different values, while data set A has more of the same values. So, data set B has more variability.\n[figure: a dot plot]\n[figure: a dot plot]", "glossary_assets/g6_variability_0.svg", ['IM-G6-U8-L2']).
im_glossary_term('G6', 'variable', "variable", "A variable is a letter that represents a number. Different numbers can be chosen for the value of the variable.\nIn the expression 10-x , the variable is x .\n- If the value of x is 3, then 10-x=7 , because 10-3=7 .\n- If the value of x is 6, then 10-x=4 , because 10-6=4 .", "", ['IM-G6-U6-L2']).
im_glossary_term('G6', 'vertex', "vertex", "A vertex is a point where 2 or more edges meet. When there is more than 1 vertex, they are called vertices.\nThe vertices of this polygon are labeled A , B , C , D , and E .\n[figure: Polygon with 5 sides]", "glossary_assets/g6_vertex.svg", ['IM-G6-U1-L10']).
im_glossary_term('G6', 'volume', "volume", "Volume is the number of cubic units that fill a three-dimensional region with no gaps or overlaps.\nThis rectangular prism has 3 layers that are each 20 units3. So, the volume of the prism is 60 units3.\n[figure: Two images. First, a prism made of cubes stacked 5 wide, 4 deep, 3 tall. Second, each of the layers of the prism is separated to show 3 prisms 5 wide, 4 deep, 1 tall.]", "glossary_assets/g6_volume.svg", ['IM-G6-U1-L16']).
im_glossary_term('G7', 'absolute_value', "absolute value", "The absolute value of a number is its distance from 0 on the number line.\n- The absolute value of -7 is 7, because it is 7 units away from 0.\n- The absolute value of 5 is 5, because it is 5 units away from 0.\n[figure: Horizontal number line, tick marks every 1 unit from -7 to 7. Above, there is a horizontal segment from -7 to 0 labeled 7, and a horizontal segment from 0 to 5 labeled 5.]", "glossary_assets/g7_absolute_value.svg", []).
im_glossary_term('G7', 'adjacent_angles', "adjacent angles", "Adjacent angles share a side and a vertex.\nIn this diagram, angle ABC is adjacent to angle DBC .\n[figure: Three segments all joined at endpoint B. Point A is to the left of B and segment A B is drawn. Point C is above B and segment C B is drawn. Point D is to the right of B and segment B D is drawn.]", "glossary_assets/g7_adjacent_angles.svg", ['IM-G7-U7-L1']).
im_glossary_term('G7', 'area', "area", "Area is the number of square units that cover a two-dimensional region without gaps or overlaps.\n- The area of region A is 8 square units.\n- The area of the shaded region of B is \\frac12 square unit.\n[figure: Figure A on the left composed of 8 identical shaded squares arranged in 3 rows. Figure B on the right consists of one square with a diagonal segment from corner to corner. Half of the square is shaded.]", "glossary_assets/g7_area.svg", []).
im_glossary_term('G7', 'area_of_a_circle', "area of a circle", "The area of a circle is the number of square units it covers. If a circle has radius r units, its area is \\pi r^2 square units.\nFor example, a circle has radius of 3 inches. Its area is \\pi 3^2 , or 9\\pi , square inches. This is about 28.3 square inches.", "", ['IM-G7-U3-L7']).
im_glossary_term('G7', 'base_of_a_prism_or_pyramid', "base (of a prism or pyramid)", "A base is a specific face of a prism or pyramid.\nA prism has 2 identical bases that are parallel. A pyramid has 1 base.\nA prism or pyramid is named for the shape of its base.\n[figure: A pentagonal prism. There are two identical pentagons on the top and bottom. Each vertex of a pentagon is connected by a vertical segment to the corresponding vertex of the other pentagons. The pengatons are each shaded, with the word base pointing to each.]\n[figure: A hexagonal pyramid. There is a hexagon on the bottom shaded green. From a point above the hexagon extend 6 segments, each connected to a vertex of the hexagon.]", "glossary_assets/g7_base_of_a_prism_or_pyramid_0.svg", ['IM-G7-U7-L11']).
im_glossary_term('G7', 'chance_experiment', "chance experiment", "A chance experiment is something that can be done over and over again, and what will happen each time is not known.\nFor example, each time the spinner is spun, it could land on red, yellow, blue, or green.\n[figure: A spinner]", "glossary_assets/g7_chance_experiment.svg", ['IM-G7-U8-L2']).
im_glossary_term('G7', 'circle', "circle", "A circle is made of all the points that are the same distance from a given point. That given point is the center of the circle.\nEvery point on this circle is 5 cm away from point A .\n[figure: A circle with points A, B, C, D, E, F]", "glossary_assets/g7_circle.svg", ['IM-G7-U3-L2']).
im_glossary_term('G7', 'circumference', "circumference", "The circumference of a circle is the distance around the circle. If a circle has radius r units, its circumference is 2\\pi r units.\nFor example, a circle has a radius of 3 inches. Its circumference is 2 \\boldcdot \\pi \\boldcdot 3 , or 6\\pi inches. This is about 18.85 inches.", "", ['IM-G7-U3-L2']).
im_glossary_term('G7', 'complementary', "complementary", "Complementary angles have measures that add up to 90 ^\\circ .\nFor example, a 15^\\circ angle and a 75^\\circ angle are complementary.\n[figure: complementary angles of 15 and 75 degrees]\n[figure: Two angles, one is 75 degrees and one is 15 degrees]", "glossary_assets/g7_complementary_0.svg", ['IM-G7-U7-L2']).
im_glossary_term('G7', 'constant_of_proportionality', "constant of proportionality", "In a proportional relationship, the values for one quantity are each multiplied by the same number to get the values for the other quantity. This number is called the constant of proportionality.\nIn this example, the constant of proportionality is 3.", "glossary_assets/g7_constant_of_proportionality.svg", ['IM-G7-U2-L2']).
im_glossary_term('G7', 'coordinate_plane', "coordinate plane", "The coordinate plane is one way to represent pairs of numbers. The plane is made of a horizontal number line and a vertical number line that cross at 0.\nPairs of numbers can be used to describe the location of a point in the coordinate plane.\nPoint R is located at (3,\\text-2) . This means R is 3 units to the right and 2 units down from (0,0) .\n[figure: Point R on a coordinate plane. Horizontal and vertical axis scale negative 4 to 4 by 1’s. The point has coordinates R 3 comma negative 2.]", "glossary_assets/g7_coordinate_plane.svg", []).
im_glossary_term('G7', 'corresponding', "corresponding", "Corresponding parts are the parts that match up between a figure and its scaled copy. They have the same relative position. Points, segments, angles, or distances can be corresponding.\nPoint B in the first triangle corresponds to point E in the second triangle. Segment AC corresponds to segment DF .\n[figure: Two triangles.]", "glossary_assets/g7_corresponding.svg", ['IM-G7-U1-L2']).
im_glossary_term('G7', 'cross_section', "cross-section", "A cross-section is the new face that is seen when a three-dimensional figure is sliced.\nA rectangular pyramid is sliced parallel to the base. The cross-section is a smaller rectangle.\n​​​​​\n[figure: A plane cuts the pyramid parallel to the base.]", "glossary_assets/g7_cross_section.png", ['IM-G7-U7-L11']).
im_glossary_term('G7', 'deposit', "deposit", "A deposit is when money is put into an account.\nFor example, a person added $60 to their bank account. Before the deposit, they had $435. After the deposit, they had $495, because 435+60=495 .", "", ['IM-G7-U5-L4']).
im_glossary_term('G7', 'diameter', "diameter", "A diameter is a line segment that goes from one point on a circle to another and passes through the center. The length of this segment is also called the diameter. Every diameter of a circle is the same length.\n[figure: A circle with its diameter labeled]", "glossary_assets/g7_diameter.svg", ['IM-G7-U3-L2']).
im_glossary_term('G7', 'equivalent_expressions', "equivalent expressions", "Equivalent expressions are always equal to each other. If the expressions have variables, they are equal whenever the same value is used for the variable in each expression.\nFor example, 3x+4x is equivalent to 5x+2x .\n- When x is 3, both expressions equal 21.\n- When x is 10, both expressions equal 70.\n- When x is any other number, both expressions still have equal value.", "", ['IM-G7-U6-L3']).
im_glossary_term('G7', 'equivalent_ratios', "equivalent ratios", "Two ratios are equivalent if each of the numbers in the first ratio can be multiplied by the same factor to get the numbers in the second ratio. For example, 8:6 is equivalent to 4:3 , because 8\\boldcdot\\frac12 = 4 and 6\\boldcdot\\frac12 = 3 .\nA recipe for lemonade says to use 8 cups of water and 6 lemons. If 4 cups of water and 3 lemons are used, it will make half as much lemonade. Both recipes taste the same, because 8:6 and 4:3 are equivalent ratios.\ncups of water\nnumber of lemons\n8\n6\n4\n3", "", []).
im_glossary_term('G7', 'event', "event", "An event is a set of 1 or more outcomes in a chance experiment.\nFor example, if a number cube is rolled, there are 6 possible outcomes.\n[figure: An image showing the six different sides of a number cube.]\nSome events are “rolling a number less than 3,” “rolling an even number,” or “rolling a 5.”", "glossary_assets/g7_event.svg", ['IM-G7-U8-L2']).
im_glossary_term('G7', 'expand', "expand", "To expand an expression, use the distributive property to rewrite a product as a sum. The new expression is equivalent to the original expression.\nFor example, the expression 5(4x+7) can be expanded to get the equivalent expression 20x + 35 .", "", ['IM-G7-U6-L19']).
im_glossary_term('G7', 'factor_an_expression', "factor (an expression)", "To factor an expression, use the distributive property to rewrite a sum as a product. The new expression is equivalent to the original expression.\nFor example, the expression 20x + 35 can be factored to get the equivalent expression 5(4x+7) .", "", ['IM-G7-U6-L19']).
im_glossary_term('G7', 'interquartile_range_iqr', "interquartile range (IQR)", "The interquartile range is one way to measure how spread out a data set is. To find the IQR, subtract the first quartile (Q1) from the third quartile (Q3).\nFor example, the IQR of this data set is 20 because 50-30=20 .\n22\n29\n30\n31\n32\n43\n44\n45\n50\n50\n59\nQ1\nQ2\nQ3", "", []).
im_glossary_term('G7', 'long_division', "long division", "Long division is a way to show the steps for dividing numbers in decimal form. It finds the quotient one digit at a time, from left to right.\nHere is the long division for 512 \\div 4 .", "glossary_assets/g7_long_division.svg", ['IM-G7-U4-L5']).
im_glossary_term('G7', 'mean', "mean", "The mean is one way to measure the center of a data set. It can be thought of as a balance point. To find the mean, add all the numbers in the data set. Then divide by how many numbers there are.\n- Data set: 7, 9, 12, 13, 14\n- Add values: 7+9+12+13+14=55\n- Divide by number of values: 55 \\div 5 = 11\nThe mean is 11. So, the typical travel time is 11 minutes.", "glossary_assets/g7_mean.svg", ['IM-G7-U8-L11']).
im_glossary_term('G7', 'mean_absolute_deviation_mad', "mean absolute deviation (MAD)", "The mean absolute deviation (MAD) is one way to measure how spread out a data set is. To find the MAD, find the distance between each data value and the mean. Add all the distances. Then divide by how many distances there are.\n- Data set: 7, 9, 12, 13, 14\n- Add distances: 4+2+1+2+3=12\n- Divide by number of distances: 12 \\div 5 = 2.4\nThe MAD is 2.4. So, these travel times are typically 2.4 minutes away from the mean of 11 minutes.\n[figure: data set for travel time in minutes with a mean of 11 minutes]", "glossary_assets/g7_mean_absolute_deviation_mad.svg", ['IM-G7-U8-L11']).
im_glossary_term('G7', 'measurement_error', "measurement error", "Measurement error is the positive difference between a measured amount and the actual amount.\nFor example, Diego measures a line segment as 5.30 cm. The actual length is 5.32 cm. The measurement error is 0.02 cm, because 5.32-5.30=0.02 .", "", ['IM-G7-U4-L13']).
im_glossary_term('G7', 'median', "median", "The median is one way to measure the center of a data set. It is the middle number when the data set is listed in order of value.\n- For the data set 7, 9, 12, 13, 14, the median is 12.\n- For the data set 3, 5, 6, 8, 11, 12, there are 2 numbers in the middle. The median is the average of these 2 numbers. 6+8=14 , and 14 \\div 2 = 7 . The median is 7.", "", ['IM-G7-U8-L11']).
im_glossary_term('G7', 'negative_number', "negative number", "A negative number is a number that is less than 0.\n[figure: number line with arrow that extends from 0 to -7]", "glossary_assets/g7_negative_number.svg", ['IM-G7-U5-L1']).
im_glossary_term('G7', 'opposite', "opposite", "Two numbers are opposites if they are the same distance from 0 on the number line, but on different sides. One is negative, and the other is positive.\n[figure: used in:]", "glossary_assets/g7_opposite.svg", ['IM-G7-U5-L3']).
im_glossary_term('G7', 'origin', "origin", "The origin is the point (0,0) in the coordinate plane. This is where the horizontal axis and the vertical axis cross. The origin is sometimes marked with the symbol \\mathcal{O} .\n[figure: a coordinate plane]", "glossary_assets/g7_origin.svg", ['IM-G7-U2-L10']).
im_glossary_term('G7', 'outcome', "outcome", "An outcome of a chance experiment is one of the things that can happen.\nFor example, the possible outcomes of tossing a coin are heads and tails.", "", ['IM-G7-U8-L2']).
im_glossary_term('G7', 'percent_decrease', "percent decrease", "A percent decrease tells how much a quantity went down. It is written as a percentage of the starting amount.\nFor example, a store had 64 hats on Friday. It had 48 hats left on Saturday. The number of hats went down by 16.\nThis was a 25% decrease, because 16 is 25% of 64.\n[figure: a tape diagram]", "glossary_assets/g7_percent_decrease.svg", ['IM-G7-U4-L6']).
im_glossary_term('G7', 'percent_error', "percent error", "Percent error is a way to describe error as a percentage of the actual amount.\nFor example, a box is supposed to have 150 folders. Clare counts only 147 folders in the box. This is an error of 3 folders. The percent error is 2%, because 3 is 2% of 150.", "", ['IM-G7-U4-L14']).
im_glossary_term('G7', 'percent_increase', "percent increase", "A percent increase tells how much a quantity went up. It is written as a percentage of the starting amount.\nFor example, Elena had $50 in the bank on Monday. She had $56 on Tuesday. The amount went up by $6.\nThis was a 12% increase, because 6 is 12% of 50.\n[figure: Tape diagram. 2 parts labeled 50 and 6. 50, 100 percent, 6, 12 percent. Total, 112 percent.]", "glossary_assets/g7_percent_increase.svg", ['IM-G7-U4-L6']).
im_glossary_term('G7', 'percentage', "percentage", "A percentage is a rate per 100.\nFor example, a fish tank can hold 36 liters. There are 27 liters of water in the tank. The percentage of the tank that is full is 75%.\n[figure: a double number line]", "glossary_assets/g7_percentage.svg", []).
im_glossary_term('G7', 'pi', "pi ()", "There is a proportional relationship between the diameter and circumference of any circle. The constant of proportionality is pi. The symbol for pi is \\pi .\nThis relationship can be represented with the equation C=\\pi d , where C represents the circumference and d represents the diameter. In the graph, pi can be seen as the value of C when the value of d is 1.\nSome approximations for \\pi are \\frac{22}{7} , 3.14, and 3.14159.\n[figure: a graph in the coordinate plane]", "glossary_assets/g7_pi.svg", ['IM-G7-U3-L3']).
im_glossary_term('G7', 'population', "population", "A population is a set of people or things that is studied.\nFor example, someone wants to study the heights of people on different sports teams. The population is all the people on all of the teams.", "", ['IM-G7-U8-L12']).
im_glossary_term('G7', 'positive_number', "positive number", "A positive number is a number that is greater than 0.\n[figure: Number line with green arrow extending from 0 to 7]", "glossary_assets/g7_positive_number.svg", ['IM-G7-U5-L1']).
im_glossary_term('G7', 'prism', "prism", "A prism is a type of polyhedron with 2 bases that are identical and parallel. The bases are connected by parallelograms.\nHere are some drawings of prisms.\n[figure: A triangular prism.]\n[figure: A pentagonal prism.]\n[figure: A rectangular prism.]", "glossary_assets/g7_prism_0.svg", ['IM-G7-U7-L11']).
im_glossary_term('G7', 'probability', "probability", "The probability of an event is a number that tells how likely it is to happen. A probability of 1 means the event will always happen. A probability of 0 means the event will never happen.\nFor example, the probability of selecting a moon block at random from this bag is \\frac45 .\n[figure: image representing a bag containing blocks]", "glossary_assets/g7_probability.svg", ['IM-G7-U8-L3']).
im_glossary_term('G7', 'proportion', "proportion", "A proportion of a data set is the fraction of the data in a given category.\nFor example, a class has 20 students. There are 2 left-handed students and 18 right-handed students in the class. The proportion of students who are left-handed is \\frac{2}{20} , or 0.1.", "", ['IM-G7-U8-L16']).
im_glossary_term('G7', 'proportional_relationship', "proportional relationship", "In a proportional relationship, the values for one quantity are each multiplied by the same number to get the values for the other quantity.\nThis table shows a proportional relationship between s and p . Each value of p is 4 times a value of s . This relationship can be written as p = 4s .\ns\np\n2\n8\n3\n12\n5\n20\n10\n40", "", ['IM-G7-U2-L2']).
im_glossary_term('G7', 'pyramid', "pyramid", "A pyramid is a type of polyhedron that has 1 base. All the other faces are triangles that meet at a single vertex.\nHere are some drawings of pyramids.\n[figure: A rectangular pyramid.]\n[figure: A hexagonal pyramid.]\n[figure: A heptagonal pyramid.]", "glossary_assets/g7_pyramid_0.svg", ['IM-G7-U7-L11']).
im_glossary_term('G7', 'radius', "radius", "A radius is a line segment that goes from the center of a circle to any point on the circle. The length of this segment is also called the radius. Every radius of a circle is the same length.\nFor example, r is the radius of this circle with center O .\n[figure: a circle with a labeled radius]", "glossary_assets/g7_radius.svg", ['IM-G7-U3-L2']).
im_glossary_term('G7', 'random', "random", "An outcome of a chance experiment is random if it cannot be predicted. For example, the result of rolling a standard number cube is random because it could result in 1, 2, 3, 4, 5, or 6, and nobody can know which value it will be until it is rolled.", "", ['IM-G7-U8-L3']).
im_glossary_term('G7', 'rational_number', "rational number", "A rational number is a number that can be written as a positive fraction, a negative fraction, or zero.\n- 8 and -8 are rational numbers because they can be written as \\frac81 and \\text-\\frac81 .\n- 0.75 and -0.75 are rational numbers because they can be written as \\frac{75}{100} and \\text-\\frac{75}{100} .", "", []).
im_glossary_term('G7', 'reciprocal', "reciprocal", "Two numbers that multiply to equal 1 are reciprocals.\n- 8 and \\frac{1}{8} are reciprocals because 8 \\boldcdot \\frac{1}{8} = 1 .\n-\n\\frac{2}{5} is a reciprocal of \\frac{5}{2} because \\frac{2}{5} \\boldcdot \\frac{5}{2} = 1 .", "", ['IM-G7-U1-L5']).
im_glossary_term('G7', 'repeating_decimal', "repeating decimal", "A repeating decimal has digits that keep going in the same pattern over and over. The repeating digits are marked with a line above them.\n- The decimal representation for \\frac13 is 0.\\overline{3} , which means 0.3333333 . . . .\n- The decimal representation for \\frac{25}{22} is 1.1\\overline{36} , which means 1.136363636 . . . .", "", ['IM-G7-U4-L5']).
im_glossary_term('G7', 'representative', "representative", "A sample is representative of a population if they match closely. They are very alike in shape, center, and spread.\nThis dot plot shows the distribution for a population.\n[figure: A dot plot labeled dollars per pound of catfish. The numbers 1.6 through 2.8 in increments of zero point 2 are indicated.]\nThis dot plot shows the distribution of a sample that is representative of the population.​​​​​\n[figure: A dot plot labeled dollars per pound of catfish. The numbers 1.6 through 2.8 in increments of zero point 2 are indicated.]", "glossary_assets/g7_representative_0.svg", ['IM-G7-U8-L13']).
im_glossary_term('G7', 'right_angle', "right angle", "A right angle is half of a straight angle. It measures 90 degrees.\n[figure: a right angle]", "glossary_assets/g7_right_angle.svg", ['IM-G7-U7-L1']).
im_glossary_term('G7', 'sample', "sample", "A sample is part of a population. For example, a population could be all the seventh grade students at one school. One sample of that population is all the seventh grade students who are in band.", "", ['IM-G7-U8-L12']).
im_glossary_term('G7', 'sample_space', "sample space", "The sample space is the list of every possible outcome for a chance experiment.\nFor example, the sample space for tossing two coins is:\nheads-heads\ntails-heads\nheads-tails\ntails-tails", "", ['IM-G7-U8-L3']).
im_glossary_term('G7', 'scale', "scale", "A scale tells how the measurements in a scale drawing represent the actual measurements.\nThe scale on this floor plan tells us that 1 inch on the drawing represents 8 feet in the actual room. This means that 2 inches represent 16 feet, and \\frac12 inch represents 4 feet.\n[figure: a floor plan with a scale of 1 inch equals 8 feet]", "glossary_assets/g7_scale.png", ['IM-G7-U1-L7']).
im_glossary_term('G7', 'scale_drawing', "scale drawing", "A scale drawing represents an actual place or object. All the measurements in the drawing correspond to the measurements of the actual object by the same scale.\n[figure: a to-scale map of part of Oklahoma]", "glossary_assets/g7_scale_drawing.png", ['IM-G7-U1-L7']).
im_glossary_term('G7', 'scale_factor', "scale factor", "To create a scaled copy of a figure, all the side lengths in the original figure are multiplied by the same number. This number is called the scale factor.\nIn this example, the scale factor is 1.5, because 4 \\boldcdot (1.5) = 6 , 5 \\boldcdot (1.5)=7.5 , and 6 \\boldcdot (1.5)=9 .\n[figure: Two triangles.]", "glossary_assets/g7_scale_factor.svg", ['IM-G7-U1-L2']).
im_glossary_term('G7', 'scaled_copy', "scaled copy", "A scaled copy is a copy of a figure where every side length in the original figure is multiplied by the same number.\nTriangle DEF is a scaled copy of triangle ABC . Each side length on triangle ABC is multiplied by 1.5 to get the corresponding side length on triangle DEF .\n[figure: Two triangles.]", "glossary_assets/g7_scaled_copy.svg", ['IM-G7-U1-L1']).
im_glossary_term('G7', 'simulation', "simulation", "A simulation is an experiment that is used to estimate the probability of a real-world event.\nSuppose the weather forecast says there is a 25% chance of rain. This situation can be simulated with a spinner that has four equal sections. If the spinner stops on red, it represents rain. If the spinner stops on any other color, it represents no rain.\n[figure: A circular spinner divided into 4 equal parts.]", "glossary_assets/g7_simulation.svg", ['IM-G7-U8-L6', 'IM-G7-U8-L7']).
im_glossary_term('G7', 'solution_to_an_equation', "solution to an equation", "A solution to an equation is a number that can be used in place of the variable to make the equation true.\n- The solution to the equation m+1=8 is 7, because it is true that 7+1=8 .\n- The solution to m+1=8 is not 9, because 9+1 does not equal 8.", "", ['IM-G7-U5-L11']).
im_glossary_term('G7', 'solution_to_an_inequality', "solution to an inequality", "A solution to an inequality is a number that can be used in place of the variable to make the inequality true.\n- A solution to the inequality c is 5, because it is true that 5.\n- Some other solutions to this inequality are 9.9, 0, and -4.", "", ['IM-G7-U6-L14']).
im_glossary_term('G7', 'squared', "squared", "The word squared means “to the second power.” This is because a square with side length s has an area of s \\boldcdot s , or s^2 .", "", ['IM-G7-U3-L8']).
im_glossary_term('G7', 'straight_angle', "straight angle", "A straight angle is an angle that forms a straight line. It measures 180 degrees.\n[figure: a 180 degree angle]", "glossary_assets/g7_straight_angle.svg", ['IM-G7-U7-L1']).
im_glossary_term('G7', 'supplementary', "supplementary", "Supplementary angles have measures that add up to 180 ^\\circ .\nFor example, a 15^\\circ angle and a 165^\\circ angle are supplementary.\n[figure: supplementary angles of 15 and 165 degrees]\n[figure: supplementary angles of 15 and 165 degrees]", "glossary_assets/g7_supplementary_0.svg", ['IM-G7-U7-L2']).
im_glossary_term('G7', 'surface_area', "surface area", "The surface area of a polyhedron is the number of square units that covers all of its faces with no gaps or overlaps.\nFor example, the 6 faces of a cube each have an area of 9 cm2. So, the surface area of the cube is 6 \\boldcdot 9 , or 54 cm2.", "", ['IM-G7-U7-L14']).
im_glossary_term('G7', 'tape_diagram', "tape diagram", "A tape diagram is a group of rectangles put together to represent a relationship between quantities.\nThis tape diagram shows a ratio of 30 gallons of yellow paint to 50 gallons of blue paint.\n[figure: tape diagrams]\nThis tape diagram represents the equivalent ratio of 15 gallons of yellow paint to 25 gallons of blue paint.\n[figure: This tape diagram represents the equivalent ratio of 15 gallons of yellow paint to 25 gallons of blue paint.]", "glossary_assets/g7_tape_diagram_0.svg", []).
im_glossary_term('G7', 'term', "term", "Terms are the parts of an expression that are added together. They can be a single number, a variable, or a number and a variable that are multiplied together.\n- 7, y , and 9a are examples of terms.\n- The expression 5x+3-18 has 3 terms: 5x , 3, and -18.", "", ['IM-G7-U6-L18']).
im_glossary_term('G7', 'unit_rate', "unit rate", "A unit rate is a rate per 1.\nFor example, 12 people share 2 pies equally. One unit rate is 6 people per pie, because 12 \\div 2 = 6 . The other unit rate is \\frac16 of a pie per person, because 2 \\div 12 = \\frac16 .", "", ['IM-G7-U4-L2']).
im_glossary_term('G7', 'variable', "variable", "A variable is a letter that represents a number. Different numbers can be chosen for the value of the variable.\nIn the expression 10-x , the variable is x .\n- If the value of x is 3, then 10-x=7 , because 10-3=7 .\n- If the value of x is 6, then 10-x=4 , because 10-6=4 .", "", []).
im_glossary_term('G7', 'vertical_angles', "vertical angles", "Vertical angles are opposite angles that share the same vertex. They are formed when two lines cross each other. Their angle measures are equal.\nAngles AEC and DEB are vertical angles. If angle AEC measures 120^\\circ , then angle DEB must also measure 120^\\circ .\nAngles AED and BEC are another pair of vertical angles.\n[figure: a pair of intersecting lines that create vertical angles.]", "glossary_assets/g7_vertical_angles.svg", ['IM-G7-U7-L3']).
im_glossary_term('G7', 'volume', "volume", "Volume is the number of cubic units that fill a three-dimensional region with no gaps or overlaps.\nThis rectangular prism has 3 layers that are each 20 units3. So, the volume of the prism is 60 units3.\n[figure: Two images. First, a prism made of cubes stacked 5 wide, 4 deep, 3 tall. Second, each of the layers of the prism is separated to show 3 prisms 5 wide, 4 deep, 1 tall.]", "glossary_assets/g7_volume.svg", ['IM-G7-U7-L12']).
im_glossary_term('G7', 'withdrawal', "withdrawal", "A withdrawal is when money is taken out of an account.\nFor example, a person took out $25 from their bank account. Before the withdrawal, they had $350. After the withdrawal, they had $325, because 350-25=325 .", "", ['IM-G7-U5-L4']).
im_glossary_term('G8', 'alternate_interior_angles', "alternate interior angles", "Alternate interior angles are created when 2 parallel lines are crossed by another line. This line is called a transversal. Alternate interior angles are inside the parallel lines and on opposite sides of the transversal.\nThis diagram shows 2 pairs of alternate interior angles:\n- Angles a and d\n- Angles b and c\n[figure: Two horizontal parallel lines and a third diagonal line labeled transversal. Angles a b c and d.]", "glossary_assets/g8_alternate_interior_angles.svg", ['IM-G8-U1-L14']).
im_glossary_term('G8', 'base_of_an_exponent', "base (of an exponent)", "In expressions like 5^3 and 8^2 , the 5 and the 8 are bases. They tell what factor is multiplied repeatedly. For example, 5^3 = 5 \\boldcdot 5 \\boldcdot 5 , and 8^2 = 8 \\boldcdot 8 .", "", ['IM-G8-U7-L1']).
im_glossary_term('G8', 'clockwise', "clockwise", "The word clockwise means to turn in the same direction as the hands of a clock. The top turns to the right.\nThis diagram shows that Figure A turns clockwise to make Figure B.\n[figure: 2 polygons, A and B. Polygon A has been rotated clockwise around one of its vertices to make Polygon B. Polygon B is the image of the original polygon A.]", "glossary_assets/g8_clockwise.svg", ['IM-G8-U1-L2']).
im_glossary_term('G8', 'coefficient', "coefficient", "A coefficient is a number that is multiplied by a variable.\n- In the expression 3x+5 , the coefficient of x is 3.\n- In the expression y+5 , the coefficient of y is 1, because y=1 \\boldcdot y .", "", []).
im_glossary_term('G8', 'cone', "cone", "A cone is a three-dimensional figure like a pyramid, but the 1 base is a circle.", "", []).
im_glossary_term('G8', 'congruent', "congruent", "One figure is congruent to another if it can be moved with translations, rotations, and reflections to fit exactly over the other.\nIn this figure, Triangle A is congruent to Triangles B, C, and D.\n- A translation takes Triangle A to Triangle B.\n- A rotation takes Triangle B to Triangle C.\n- A reflection takes Triangle C to Triangle D.\n[figure: four congruent triangles]", "glossary_assets/g8_congruent.svg", ['IM-G8-U1-L11']).
im_glossary_term('G8', 'constant_of_proportionality', "constant of proportionality", "In a proportional relationship, the values for one quantity are each multiplied by the same number to get the values for the other quantity. This number is called the constant of proportionality.\nIn this example, the constant of proportionality is 3.", "glossary_assets/g8_constant_of_proportionality.svg", []).
im_glossary_term('G8', 'constant_term', "constant term", "In an expression like 5x+2 , the number 2 is called the constant term. It doesn’t change when the variable x changes.\n- In the expression 7x+9 , the constant term is 9.\n- In the expression 5x+(\\text-8) , the constant term is -8.\n- In the expression 12-4x , the constant term is 12.", "", ['IM-G8-U4-L8']).
im_glossary_term('G8', 'coordinate_plane', "coordinate plane", "The coordinate plane is one way to represent pairs of numbers. The plane is made of a horizontal number line and a vertical number line that cross at 0.\nPairs of numbers can be used to describe the location of a point in the coordinate plane.\nPoint R is located at (3,\\text-2) . This means R is 3 units to the right and 2 units down from (0,0) .\n[figure: Point R on a coordinate plane. Horizontal and vertical axis scale negative 4 to 4 by 1’s. The point has coordinates R 3 comma negative 2.]", "glossary_assets/g8_coordinate_plane.svg", []).
im_glossary_term('G8', 'corresponding', "corresponding", "Corresponding parts are the parts that match up between a figure and its scaled copy. They have the same relative position. Points, segments, angles, or distances can be corresponding.\nPoint B in the first triangle corresponds to point E in the second triangle. Segment AC corresponds to segment DF .\n[figure: Two triangles.]", "glossary_assets/g8_corresponding.svg", ['IM-G8-U1-L7']).
im_glossary_term('G8', 'counterclockwise', "counterclockwise", "The term counterclockwise means to turn opposite of the way the hands of a clock turn. The top turns to the left.\nThis diagram shows that Figure A turns counterclockwise to make Figure B.\n[figure: Two figures. Figure A turned counterclockwise makes Figure B.]", "glossary_assets/g8_counterclockwise.svg", ['IM-G8-U1-L2']).
im_glossary_term('G8', 'cube_root', "cube root", "The cube root of a number n is the number whose cube is n . It is also the edge length of a cube with a volume of n . The cube root of n is written as \\sqrt[3]{n} .\nThe cube root of 64 is written as \\sqrt[3]{64} . Its value is 4 because 4^3 is 64.\n\\sqrt[3]{64} is also the edge length of a cube that has a volume of 64.", "", ['IM-G8-U8-L14']).
im_glossary_term('G8', 'cylinder', "cylinder", "A cylinder is a three-dimensional figure like a prism, but with 2 bases that are circles.", "", []).
im_glossary_term('G8', 'dependent_variable', "dependent variable", "A dependent variable represents the output of a function.\nFor example, someone needs to buy 20 pieces of fruit and decides to buy apples and bananas. If they select the number of apples first, the equation b=20-a shows the number of bananas they can buy. The number of bananas is the dependent variable because it depends on the number of apples.", "", ['IM-G8-U5-L3']).
im_glossary_term('G8', 'dilation', "dilation", "A dilation is a transformation that can reduce or enlarge a figure. Each point on the figure moves along a line closer to or farther from a fixed point. That fixed point is the center of the dilation. All of the original distances are multiplied by the same scale factor.\nTriangle DEF is a dilation of triangle ABC . The center of dilation is O . The scale factor is 3.\nEvery point of triangle DEF is 3 times as far from O as every corresponding point of triangle ABC .\n[figure: 2 triangles. Triangle DEF is a dilation of triangle ABC.]", "glossary_assets/g8_dilation.svg", ['IM-G8-U2-L2']).
im_glossary_term('G8', 'exponent', "exponent", "In expressions like 5^3 and 8^2 , the numbers 3 and the 2 are called exponents. They tell how many times a number is used as a factor.\nFor example, 5^3 = 5 \\boldcdot 5 \\boldcdot 5 , and 8^2 = 8 \\boldcdot 8 .", "", ['IM-G8-U7-L1']).
im_glossary_term('G8', 'function', "function", "A function is a rule that has exactly 1 output for each possible input.\nIn the function y=6x+4 , x is the input and y is the output. When x is 5, y has one value, 34.\n\\begin{align} y&=6x+4\\\\ y&=6(5)+4 \\\\ y&=34 \\\\ \\end{align}", "", ['IM-G8-U5-L2']).
im_glossary_term('G8', 'hypotenuse', "hypotenuse", "The hypotenuse is the side of a right triangle that is opposite the right angle. It is the longest side of a right triangle.\nHere are some right triangles. Each hypotenuse is labeled.\n[figure: Four right triangles of different sizes and orientations each with two legs and a hypotenuse opposite the right angle.]", "glossary_assets/g8_hypotenuse.svg", ['IM-G8-U8-L7']).
im_glossary_term('G8', 'image', "image", "An image is the result of translations, rotations, and reflections on an object. Every part of the original object moves in the same way to match up with a part of the image.\nTriangle ABC has been translated up and to the right to make triangle DEF . Triangle DEF is the image of the original triangle ABC .\n[figure: 2 triangles, ABC and DEF. Triangle ABC has been translated up and to the right to make triangle DEF. Triangle DEF is the image of the original triangle ABC.]", "glossary_assets/g8_image.svg", ['IM-G8-U1-L3']).
im_glossary_term('G8', 'independent_variable', "independent variable", "An independent variable represents the input of a function.\nFor example, suppose someone needs to buy 20 pieces of fruit and decides to buy some apples and bananas. If they select the number of apples first, the equation b=20-a shows the number of bananas they can buy. The number of apples is the independent variable because any number can be chosen for it.", "", ['IM-G8-U5-L3']).
im_glossary_term('G8', 'integer', "integer", "An integer is a type of number. All whole numbers and their opposites are integers.\nThe labels on this number line show all the integers from -10 to 10.\n[figure: A number line from negative 10 to 10 by ones.]", "glossary_assets/g8_integer.svg", []).
im_glossary_term('G8', 'irrational_number', "irrational number", "An irrational number is a number that is not rational. It cannot be written as a positive fraction, a negative fraction, or zero.\nPi ( \\pi ) and \\sqrt2 are examples of irrational numbers.", "", ['IM-G8-U8-L4']).
im_glossary_term('G8', 'legs', "legs", "The legs of a right triangle are the sides that make the right angle.\nHere are some right triangles. Each leg is labeled.\n[figure: Four right triangles of different sizes and orientations each with two legs and a hypotenuse opposite the right angle.]", "glossary_assets/g8_legs.svg", ['IM-G8-U8-L7']).
im_glossary_term('G8', 'linear_relationship', "linear relationship", "Two quantities have a linear relationship when:\n- One quantity changes by a set amount, whenever the other quantity changes by a set amount.\n- The rate of change is constant.\n- The graph of the relationship is a line.\nThis graph shows a linear relationship between number of days and number of pages read.\nWhen the number of days increases by 2, the number of pages read always increases by 60. The rate of change is constant, 30 pages per day.\n[figure: Graph of line. Points plotted on line include 1 comma 70 and 4 comma 160.]", "glossary_assets/g8_linear_relationship.svg", ['IM-G8-U3-L5']).
im_glossary_term('G8', 'negative_association', "negative association", "A negative association is a relationship between 2 quantities where one tends to decrease as the other increases. In a scatter plot, the data points tend to group around a line with negative slope.\nThis scatter plot shows a negative association between the the price of a book and the number of books sold.\n[figure: Scatterplot with line of best fit.]", "glossary_assets/g8_negative_association.svg", ['IM-G8-U6-L5']).
im_glossary_term('G8', 'outlier', "outlier", "An outlier is a data value that is far from the other values in the data set.\nThis scatter plot shows 1 outlier.\n[figure: A scatterplot with line.]", "glossary_assets/g8_outlier.svg", ['IM-G8-U6-L4']).
im_glossary_term('G8', 'positive_association', "positive association", "A positive association is a relationship between 2 quantities where one tends to increase as the other increases. In a scatter plot, the data points tend to group around a line with positive slope.\nThis scatterplot shows a positive association between dog height and dog weight.\n[figure: A scatterplot, horizontal, dog height in inches, 6 to 30 by 3, vertical, 0 to 112 by 16. Same scatterplot as previous, this time with a line through 9 comma 0 and 27 comma 80.]", "glossary_assets/g8_positive_association.svg", ['IM-G8-U6-L5']).
im_glossary_term('G8', 'pythagorean_theorem', "Pythagorean Theorem", "The Pythagorean Theorem describes the relationship between the side lengths of right triangles.\nThe square of the hypotenuse is equal to the sum of the squares of the legs. This is written as a^2+b^2=c^2 .\nThis diagram shows the relationship.\n[figure: a right triangle with squares built on each side]", "glossary_assets/g8_pythagorean_theorem.svg", ['IM-G8-U8-L7']).
im_glossary_term('G8', 'radius', "radius", "A radius is a line segment that goes from the center of a circle to any point on the circle. The length of this segment is also called the radius. Every radius of a circle is the same length.\nFor example, r is the radius of this circle with center O .\n[figure: a circle with a labeled radius]", "glossary_assets/g8_radius.svg", []).
im_glossary_term('G8', 'rate_of_change_in_a_linear_relationship', "rate of change (in a linear relationship)", "The rate of change is the amount y changes when x increases by 1. On a graph, the rate of change is the slope of the line.\nIn this graph, y increases by 15 dollars when x increases by 1 hour. The rate of change is 15 dollars per hour.\n[figure: Graph, horizontal axis, x, amount earned in hours. vertical axis, y, amount earned in dollars.]", "glossary_assets/g8_rate_of_change_in_a_linear_relationship.svg", ['IM-G8-U3-L3', 'IM-G8-U3-L5']).
im_glossary_term('G8', 'rational_number', "rational number", "A rational number is a number that can be written as a positive fraction, a negative fraction, or zero. It can be written in the form \\frac{a}{b} where a and b are integers and b is not equal to 0.\nFor example, 0.7 is a rational number because it can be written as \\frac{7}{10} .\nSome examples of rational numbers: \\frac74,0,\\frac63,0.2,\\text-\\frac13,\\text-5,\\sqrt9", "", ['IM-G8-U8-L4']).
im_glossary_term('G8', 'reflection', "reflection", "A reflection is a transformation that “flips” a figure over a line. Every point on the figure moves to a point directly on the opposite side of the line. The new points are the same distance from the line as they are in the original figure.\nThis diagram shows a reflection of A over line \\ell that makes the mirror image B.\n[figure: Two triangles, A and B. A reflection of A over a line makes the mirror image B.]", "glossary_assets/g8_reflection.svg", ['IM-G8-U1-L2']).
im_glossary_term('G8', 'relative_frequency', "relative frequency", "The relative frequency of a category tells the proportion at which the category occurs in the data set. It is written as a fraction, decimal, or percentage of the total number.\nFor example, there were 21 dogs in a park. This table shows the frequency and the relative frequency of each color.\ndog color\nfrequency\nrelative frequency\nwhite\n5\n\\frac{5}{21}\nbrown\n7\n\\frac{7}{21}\nblack\n3\n\\frac{3}{21}\nmulti-color\n6\n\\frac{6}{21}", "", ['IM-G8-U6-L9']).
im_glossary_term('G8', 'repeating_decimal', "repeating decimal", "A repeating decimal has digits that keep going in the same pattern over and over. The repeating digits are marked with a line above them.\n- The decimal representation for \\frac13 is 0.\\overline{3} , which means 0.3333333 . . . .\n- The decimal representation for \\frac{25}{22} is 1.1\\overline{36} , which means 1.136363636 . . . .", "", ['IM-G8-U8-L16']).
im_glossary_term('G8', 'right_angle', "right angle", "A right angle is half of a straight angle. It measures 90 degrees.\n[figure: a right angle]", "glossary_assets/g8_right_angle.svg", []).
im_glossary_term('G8', 'rigid_transformation', "rigid transformation", "A rigid transformation is a move that does not change any measurements of a figure. Translations, rotations, and reflections are rigid transformations. So is any sequence of these.", "", ['IM-G8-U1-L7']).
im_glossary_term('G8', 'rotation', "rotation", "A rotation is a transformation that “turns” a figure. Every point on the figure moves around a center by a given angle in a specific direction.\nThis diagram shows Triangle A rotated around center O by 55 degrees clockwise to get Triangle B.\n[figure: Two triangles, A and B. Triangle A rotated by 55 degrees clockwise gets Triangle B.]", "glossary_assets/g8_rotation.svg", ['IM-G8-U1-L2']).
im_glossary_term('G8', 'scale_factor', "scale factor", "To create a scaled copy of a figure, all the side lengths in the original figure are multiplied by the same number. This number is called the scale factor.\nIn this example, the scale factor is 1.5, because 4 \\boldcdot (1.5) = 6 , 5 \\boldcdot (1.5)=7.5 , and 6 \\boldcdot (1.5)=9 .\n[figure: Two triangles.]", "glossary_assets/g8_scale_factor.svg", []).
im_glossary_term('G8', 'scatter_plot', "scatter plot", "A scatter plot is a graph that shows values of 2 variables on a coordinate plane. It can be used to look for relationships between the 2 variables.\nEach point on this scatter plot represents the height and weight of 1 dog.\n[figure: scatter plot]", "glossary_assets/g8_scatter_plot.svg", ['IM-G8-U6-L1']).
im_glossary_term('G8', 'scientific_notation', "scientific notation", "Scientific notation is a way to write very large or very small numbers. They are written as a product. The first factor is a number greater than or equal to 1, but less than 10. The second factor is a power of 10.\n- The number 425,000,000 in scientific notation is 4.25 \\times 10^8 .\n- The number 0.0000000000783 in scientific notation is 7.83 \\times 10^{\\text-11} .", "", ['IM-G8-U7-L13']).
im_glossary_term('G8', 'segmented_bar_graph', "segmented bar graph", "A segmented bar graph shows categories within a data set. Each whole bar represents all the data in one main category. Each bar is separated into parts (segments) that show subcategories.\n[figure: Stacked bar graph.]\nThis segmented bar graph shows the percentage of people in different age groups that do and do not have a cell phone. For example, among people ages 10 to 12, about 40% have a cell phone and 60% do not.", "glossary_assets/g8_segmented_bar_graph.svg", ['IM-G8-U6-L9']).
im_glossary_term('G8', 'sequence_of_transformations', "sequence of transformations", "A sequence of transformations is a set of translations, rotations, reflections, and dilations on a figure. The transformations are performed in a given order.\nThis diagram shows a sequence of transformations to move Figure A to Figure C.\nFirst, A is translated to the right to make B. Next, B is reflected across line \\ell to make C.\n[figure: Transformation taking figure A to figure B.]", "glossary_assets/g8_sequence_of_transformations.svg", ['IM-G8-U1-L4']).
im_glossary_term('G8', 'similar', "similar", "Two figures are similar if one can fit exactly over the other after transformations.\nThis figure shows triangle ABC is similar to triangle DEF .\n- Rotate triangle ABC around point B .\n- Then dilate it with center point O .\n- The image will fit exactly over triangle DEF .\n[figure: A sequence of transformations.]", "glossary_assets/g8_similar.svg", ['IM-G8-U2-L6']).
im_glossary_term('G8', 'slope', "slope", "Slope is a number that describes how steep a line is. To find the slope, divide the vertical change by the horizontal change for any 2 points on the line.\nThe slope of this line is 2 divided by 3, or \\frac23 .\n[figure: A graph in the coordinate plane with a line on it.]", "glossary_assets/g8_slope.svg", ['IM-G8-U2-L10']).
im_glossary_term('G8', 'solution_to_an_equation_with_two_variables', "solution to an equation with two variables", "A solution to an equation with 2 variables is a pair of values for the variables that make the equation true.\nFor example, one solution to the equation 4x+3y=24 is (6,0) . Substituting 6 for x and 0 for y makes this equation true because 4(6)+3(0)=24 .", "", ['IM-G8-U3-L13']).
im_glossary_term('G8', 'sphere', "sphere", "A sphere is a three-dimensional figure where any cross-section is a circle.", "", []).
im_glossary_term('G8', 'square_root', "square root", "The square root of a positive number n is the positive number whose square is n . It is also the side length of a square whose area is n . The square root of n is written as \\sqrt{n} .\nThe square root of 16 is written as \\sqrt{16} . Its value is 4 because 4^2 is 16.\n\\sqrt{16} is also the side length of a square that has an area of 16.", "", ['IM-G8-U8-L2']).
im_glossary_term('G8', 'straight_angle', "straight angle", "A straight angle is an angle that forms a straight line. It measures 180 degrees.\n[figure: a 180 degree angle]", "glossary_assets/g8_straight_angle.svg", []).
im_glossary_term('G8', 'system_of_equations', "system of equations", "A system of equations is a set of 2 or more equations. Each equation has 2 or more variables. A solution to the system is values for the variables that make all the equations true.\nThese equations make up a system of equations:\n\\displaystyle \\begin{cases} x + y = \\text-2\\\\x - y = 12\\end{cases}\nThe solution to this system is x=5 and y=\\text-7 . When these values are substituted for x and y , both equations are true: 5+(\\text-7)=\\text-2 and 5-(\\text-7)=12 .", "", ['IM-G8-U4-L12']).
im_glossary_term('G8', 'term', "term", "Terms are the parts of an expression that are added together. They can be a single number, a variable, or a number and a variable that are multiplied together.\n- 7, y , and 9a are examples of terms.\n- The expression 5x+3-18 has 3 terms: 5x , 3, and -18.", "", []).
im_glossary_term('G8', 'tessellation', "tessellation", "A tessellation is a repeating pattern of 1 or more shapes. The sides of the shapes fit together with no gaps or overlaps. The pattern goes on forever in all directions.\nThis diagram shows part of a tessellation.\n[figure: part of a tessellation]", "glossary_assets/g8_tessellation.svg", ['IM-G8-U1-L17']).
im_glossary_term('G8', 'transformation', "transformation", "A transformation is a translation, rotation, reflection, or dilation, or a combination of these.", "", ['IM-G8-U1-L4']).
im_glossary_term('G8', 'translation', "translation", "A translation is a transformation that “slides” a figure along a straight line. Every point on the figure moves a given distance in a given direction.\nThis diagram shows a translation of Figure A to Figure B using the direction and distance given by the arrow.\n[figure: A translation of triangle A to triangle B]", "glossary_assets/g8_translation.svg", ['IM-G8-U1-L2']).
im_glossary_term('G8', 'transversal', "transversal", "A transversal is a line that crosses parallel lines.\nThis diagram shows a transversal line k intersecting parallel lines m and \\ell .\n[figure: Parallel lines l and m with transversal k.]", "glossary_assets/g8_transversal.svg", ['IM-G8-U1-L14']).
im_glossary_term('G8', 'two_way_table', "two-way table", "A two-way table shows data for 2 categorical variables. One variable is shown in rows and the other in columns. Each entry is the frequency or relative frequency of the category shown by the column and row headings.\nThis two-way table shows the results of a study. The study looked at how meditation affects the way athletes feel.\nmeditated\ndid not meditate\ntotal\ncalm\n45\n8\n53\nagitated\n23\n21\n44\ntotal\n68\n29\n97", "", ['IM-G8-U6-L9']).
im_glossary_term('G8', 'vertex', "vertex", "A vertex is a point where 2 or more edges meet. When there is more than 1 vertex, they are called vertices.\nThe vertices of this polygon are labeled A , B , C , D , and E .\n[figure: Polygon with 5 sides]", "glossary_assets/g8_vertex.svg", ['IM-G8-U1-L1']).
im_glossary_term('G8', 'vertical_angles', "vertical angles", "Vertical angles are opposite angles that share the same vertex. They are formed when two lines cross each other. Their angle measures are equal.\nAngles AEC and DEB are vertical angles. If angle AEC measures 120^\\circ , then angle DEB must also measure 120^\\circ .\nAngles AED and BEC are another pair of vertical angles.\n[figure: a pair of intersecting lines that create vertical angles.]", "glossary_assets/g8_vertical_angles.svg", ['IM-G8-U1-L9']).
im_glossary_term('G8', 'vertical_intercept', "vertical intercept", "The vertical intercept is the point where the graph of a line crosses the vertical axis.\nThe vertical intercept of this line is (0,\\text-6) or just -6.\n[figure: A graph of a line with a vertical intercept of -6.]", "glossary_assets/g8_vertical_intercept.svg", ['IM-G8-U3-L6']).
im_glossary_term('G8', 'volume', "volume", "Volume is the number of cubic units that fill a three-dimensional region with no gaps or overlaps.\nThis rectangular prism has 3 layers that are each 20 units3. So, the volume of the prism is 60 units3.\n[figure: Two images. First, a prism made of cubes stacked 5 wide, 4 deep, 3 tall. Second, each of the layers of the prism is separated to show 3 prisms 5 wide, 4 deep, 1 tall.]", "glossary_assets/g8_volume.svg", []).
im_glossary_term('GK', 'above', "above", "", "glossary_assets/gK_above.svg", []).
im_glossary_term('GK', 'add', "add", "4 + 3\nfour plus three\n[figure: four plus three]", "glossary_assets/gK_add.svg", []).
im_glossary_term('GK', 'below', "below", "", "glossary_assets/gK_below.svg", []).
im_glossary_term('GK', 'beside', "beside", "", "glossary_assets/gK_beside.svg", []).
im_glossary_term('GK', 'circle', "circle", "", "glossary_assets/gK_circle.svg", []).
im_glossary_term('GK', 'cone', "cone", "[figure: A wooden cone shape with a smooth texture and subtle grain patterns.]", "glossary_assets/gK_cone.png", []).
im_glossary_term('GK', 'cube', "cube", "[figure: cube]", "glossary_assets/gK_cube.png", []).
im_glossary_term('GK', 'cylinder', "cylinder", "[figure: A simple wooden cylinder with a smooth surface and visible wood grain patterns.]", "glossary_assets/gK_cylinder.png", []).
im_glossary_term('GK', 'equation', "equation", "10 = 6 + 4\n5 - 2 = 3", "", []).
im_glossary_term('GK', 'expression', "expression", "6 + 4\n3 - 3", "", []).
im_glossary_term('GK', 'fewer', "fewer", "", "glossary_assets/gK_fewer.svg", []).
im_glossary_term('GK', 'less', "less", "3 is less than 9\n[figure: 3 is less than 9]", "glossary_assets/gK_less.svg", []).
im_glossary_term('GK', 'longer', "longer", "The straw on top is longer.\n[figure: The straw on top is longer.]", "glossary_assets/gK_longer.png", []).
im_glossary_term('GK', 'more', "more", "9 is more than 3.\n[figure: 9 is more than 3.]", "glossary_assets/gK_more.svg", []).
im_glossary_term('GK', 'next_to', "next to", "", "glossary_assets/gK_next_to.svg", []).
im_glossary_term('GK', 'number_writing_reference', "number writing reference", "1\none\n2\ntwo\n3\nthree\n4\nfour\n5\nfive\n6\nsix\n[figure: Five-frame, full. Below, 1 dot.]\n7\nseven\n8\neight\n9\nnine\n10\nten", "glossary_assets/gK_number_writing_reference_0.svg", []).
